package com.facilcomanda.auditservice.controller; import com.facilcomanda.auditservice.entity.AuditLog; import com.facilcomanda.auditservice.service.AuditService; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/api/audit") public class AuditController { private final AuditService service; public AuditController(AuditService service){this.service=service;} @GetMapping public List<AuditLog> all(){return service.all();} @GetMapping("/{id}") public AuditLog byId(@PathVariable Long id){return service.byId(id);} @GetMapping("/entity/{entityName}/{entityId}") public List<AuditLog> byEntity(@PathVariable String entityName,@PathVariable String entityId){return service.byEntity(entityName,entityId);} @GetMapping("/user/{userId}") public List<AuditLog> byUser(@PathVariable String userId){return service.byUser(userId);} }
